scwin.f_FieldClear = function () {
  ica_payYm.setValue(WebSquare.date.getCurrentServerDate().substring(0, 6));
  ica_regDt.setValue(WebSquare.date.getCurrentServerDate());
  $p.setTimeout(function () {
    ed_acctDeptCd.setValue(scwin.deptCd);
    ed_acctDeptNm.setValue(scwin.deptNm);
  }, {
    "delay": 50
  });
  chk_lowerDeptIncluYn.setValue("");
  ed_staffNo.setValue("");
  ed_staffNm.setValue("");
  acb_payGbn.setSelectedIndex(0);
};
scwin.f_Retrieve = async function () {
  if (!(await $c.gus.cfValidate($p, [searchCondition]))) {
    return;
  }
  if (chk_lowerDeptIncluYn.getValue() == "1") {
    dma_search.set("lowerDeptIncluYn", 1);
  } else {
    dma_search.set("lowerDeptIncluYn", 0);
  }
  dma_search.set("payYm", ica_payYm.getValue());
  dma_search.set("payGbn", acb_payGbn.getValue());
  dma_search.set("regDt", ica_regDt.getValue());
  // dma_search.set("acctDeptCd",acb_acctDeptCd.getValue());

  $c.sbm.execute($p, sbm_search);
};

//전표생성
scwin.f_Save = async function () {
  var cnt = 0;
  if (!(await $c.gus.cfValidate($p, [ica_regDt]))) {
    return false;
  }
  for (var i = 0; i < ds_list.getTotalRow(); i++) {
    if (ds_list.getCellData(i, "chk") == "1") {
      cnt++;
      if (ds_list.getCellData(i, "slipNo") != "") {
        await $c.gus.cfAlertMsg($p, "[" + ds_list.getCellData(i, "staffNm") + "] 이미 전표생성된 내역은 선택 불가합니다.");
        return;
      } else {
        if (ds_list.getCellData(i, "workTax") < 1000) {
          //소득세 천원 미만인 경우
          if (ds_list.getCellData(i, "taxchk") == 1) {
            //소액부징수 여부 체크
            ds_list.setCellData(i, "workTax", 0);
            ds_list.setCellData(i, "localTax", 0);
          } else {
            await $c.gus.cfAlertMsg($p, "[" + ds_list.getCellData(i, "staffNm") + "] 소액부 징수 대상입니다. \n소액부징수여부 미체크 시 소득세/지방소득세가 생성됩니다.");
          }
        }
      }
    }
  }
  if (cnt == 0) {
    await $c.gus.cfAlertMsg($p, "선택한 내역이 존재하지 않습니다.");
    return;
  }
  if ((await $c.win.confirm($p, "전표를 생성하시겠습니까?")) == true) {
    $c.sbm.execute($p, sbm_save);
  }
};

//전표삭제
scwin.f_Delete = async function () {
  var cnt = 0;
  for (var i = 0; i < ds_list.getTotalRow(); i++) {
    if (ds_list.getCellData(i, "chk") == 1) {
      cnt++;
      if (ds_list.getCellData(i, "slipNo") == "") {
        await $c.gus.cfAlertMsg($p, "[" + ds_list.getCellData(i, "staffNm") + "] 전표생성된 내역이 없습니다. 전표삭제 불가합니다.");
        return;
      }
    }
  }
  if (cnt == 0) {
    await $c.gus.cfAlertMsg($p, "선택한 내역이 존재하지 않습니다.");
    return;
  }
  if ((await $c.win.confirm($p, "전표를 삭제하시겠습니까?")) == true) {
    $c.sbm.execute($p, sbm_delete);
  }
};

// 저장 (연차수당, 공제내역, 보소지급기초일수 UPDATE)
scwin.f_Update = async function () {
  var cnt = 0;
  for (var i = 0; i < ds_list.getTotalRow(); i++) {
    if (ds_list.getCellData(i, "chk") == 1) {
      cnt++;
      if (ds_list.getCellData(i, "slipNo") != "") {
        await $c.gus.cfAlertMsg($p, "[" + ds_list.getCellData(i, "staffNm") + "] 이미 전표생성된 내역은 수정할 수 없습니다.");
        return;
      }
    }
  }
  if (cnt == 0) {
    await $c.gus.cfAlertMsg($p, "선택한 내역이 존재하지 않습니다.");
    return;
  }
  if (ds_list.getModifiedIndex() == 0) {
    await $c.gus.cfAlertMsg($p, "변경된 사항이 없습니다.");
    return;
  }
  if ((await $c.win.confirm($p, "저장 하시겠습니까?")) == true) {
    $c.sbm.execute($p, sbm_update);
  }
};

// function Parameter : inObj : 코드값, pairObj : 코드명, disGubun : 구분, isCode : 코드구분(코드, 명칭)
scwin.f_chkOpenCommonPopUp = function (inObj, pairObj, disGubun, isCode) {
  // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
  if (!$c.gus.cfCanOpenPopup($p, inObj, pairObj)) return;

  // 짝이 되는 오브젝트의 값 제거
  $c.gus.cfClearPairObj($p, pairObj);

  // 검색어 세팅
  var pVal = $c.gus.cfGetValue($p, inObj);
  // inObj가 코드 필드일 경우 팝업

  if (isCode == null || isCode == true) {
    scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
    // inObj가 코드명 필드일 경우 팝업
  } else {
    scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
  }
};

// function Parameter : disGubun : 구분, pCode : 코드, pName : 코드명, pClose : 창여부, pAllSearch : 전체허용여부
scwin.f_openCommonPopUp = function (disGubun, pCode, pName, pClose, pAllSearch) {
  // 선언부
  var rtnList; // 공통POP-UP -> 요청화면 
  switch (disGubun) {
    case 1:
      // 귀속부서
      var param = "," + ed_coCd.getValue() + "," + scwin.txtCoClsCd;
      rtnList = udc_retrieveAcctDept.cfCommonPopUp(scwin.udc_retrieveAcctDept_callBack, pCode, pName, pClose, null, null, null, null, param, null, null, null, null);
      break;
    case 2:
      // 일용직 사원정보
      var param = "," + ed_coCd.getValue();
      rtnList = udc_staffList.cfCommonPopUp(scwin.udc_staffList_callBack // XML상의 SELECT ID  
      , pCode // 화면에서의 ??? Code Element의  Value
      , pName // 화면에서의 ??? Name Element의  Value
      , pClose // 결과가 1건 일때  원도우를  AutoClose 여부    (T:Close,F:Opened)
      , null // 검색 결과    컬럼의 보여주는    개수 (SELECT절의 순서) MAX:10 - default (2)
      , null // Title순서  
      , null // 보여주는 각 컬럼들의 폭    
      , null // 컬럼중에서 숨기는    컬럼 지정   
      , "1" // SQL절의 WHERE절에    원하는 조건을 선택함 MAX:8개까지 가능
      , null // POP-UP뛰을때 원도우의   사용자 정의  폭
      , null // POP-UP뛰을때 우도우의   사용자 정의  높이  
      , param // 윈도우 위치 Y좌표   
      , null // 윈도우 위치 X좌표
      , null // 중복체크여부   ("F")
      , pAllSearch // 전체검색허용여부 ("F")
      , "인원,사번,인원명" // POP-UP Window Title 검색어1,2    ("Win타이틀,첫번검색Nm,두번?검색Nm")
      );
      break;
  }
};
scwin.udc_retrieveAcctDept_callBack = function (rtnList) {
  // $c.gus.cfSetReturnValue(rtnList, ed_acctDeptCd, ed_acctDeptNm);

  if (rtnList != null) {
    if (rtnList[0] == "N/A") return;
    ed_acctDeptCd.setValue(rtnList[0]); // 코드
    ed_acctDeptNm.setValue(rtnList[1]); // 회사명
    ed_acctDeptCd.options.hidVal = rtnList[0];
  } else {
    ed_acctDeptCd.setValue("");
    ed_acctDeptNm.setValue("");
    ed_acctDeptCd.options.hidVal = "";
  }
};
