scwin.sbm_search_submitdone = async function (e) {
  var rowCnt = ds_list.getTotalRow();
  ed_totalRow.setValue(rowCnt);
  if (rowCnt == 0) {
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_003);
    $c.gus.cfDisableBtnOnly($p, [btn_SlipCreate, btn_SlipDel, btn_Save]);
    return;
  }
  $c.gus.cfEnableBtnOnly($p, [btn_SlipCreate, btn_SlipDel, btn_Save]);
  for (let i = 0; i < rowCnt; i++) {
    ds_list.setCellData(i, "totPayAmt1", Number(ds_list.getCellData(i, "totPayAmt")) + Number(ds_list.getCellData(i, "etcDedtAmt")));
    if (ds_list.getCellData(i, "slipNo") == "") {
      if (ds_list.getCellData(i, "chk") == "1") {
        gr_list.setReadOnly("cell", i, "pensionDedtAmt", false);
        gr_list.setReadOnly("cell", i, "healthDedtAmt", false);
        gr_list.setReadOnly("cell", i, "unempDedtAmt", false);
        gr_list.setReadOnly("cell", i, "workTax", false);
        gr_list.setReadOnly("cell", i, "localTax", false);
        gr_list.setReadOnly("cell", i, "taxchk", false);
        gr_list.setReadOnly("cell", i, "payBasicDay", false);
      } else {
        gr_list.setReadOnly("cell", i, "pensionDedtAmt", true);
        gr_list.setReadOnly("cell", i, "healthDedtAmt", true);
        gr_list.setReadOnly("cell", i, "unempDedtAmt", true);
        gr_list.setReadOnly("cell", i, "workTax", true);
        gr_list.setReadOnly("cell", i, "localTax", true);
        gr_list.setReadOnly("cell", i, "taxchk", true);
        gr_list.setReadOnly("cell", i, "payBasicDay", true);
      }
    } else {
      gr_list.setReadOnly("cell", i, "pensionDedtAmt", true);
      gr_list.setReadOnly("cell", i, "healthDedtAmt", true);
      gr_list.setReadOnly("cell", i, "unempDedtAmt", true);
      gr_list.setReadOnly("cell", i, "workTax", true);
      gr_list.setReadOnly("cell", i, "localTax", true);
      gr_list.setReadOnly("cell", i, "taxchk", true);
      gr_list.setReadOnly("cell", i, "payBasicDay", true);
    }
  }
};
scwin.sbm_save_submitdone = async function (e) {
  if (e.responseJSON.resultDataSet[0].Msg != "FAIL") {
    await $c.gus.cfAlertMsg($p, MSG_CM_INF_001); //"성공적으로 저장하였습니다."
    scwin.f_Retrieve();
    var position = ds_slipNo.getRowPosition();
    if (position == "" || position == null) {
      position = 0;
    }
    if (ds_slipNo.getCellData(position, "slipNo") != "") {
      $c.gus.cfShowSlipInfo($p, ds_slipNo.getCellData(position, "slipNo"));
    }
  }
};
