scwin.gr_list_oncellclick = function (rowIndex, columnIndex, columnId) {
  var Colid = gr_list.getColumnID(columnIndex);
  // 전표번호가 존재하는 행 선택시 동일한 전표번호 행 모두 선택
  if (Colid == "chk") {
    if (!$c.gus.cfIsNull($p, ds_list.getCellData(rowIndex, "slipNo"))) {
      for (i = 0; i < ds_list.getTotalRow(); i++) {
        if (ds_list.getCellData(rowIndex, "slipNo") == ds_list.getCellData(i, "slipNo")) {
          ds_list.setCellData(i, "chk", ds_list.getCellData(rowIndex, "chk"));
        }
      }
    }
  }

  // 전표번호 선택 시
  if (Colid == "slipNo" && !$c.gus.cfIsNull($p, ds_list.getCellData(rowIndex, "slipNo"))) {
    $c.gus.cfShowSlipInfo($p, ds_list.getCellData(ds_list.getRowPosition(), "slipNo"));
  }
};
